function getFirst<T>(items: T[]): T | undefined {
  return items[0]
}

function getFirstRequired<T>(items: T[]): T {
  const first = items[0]
  if (first === undefined) throw new Error("Array is empty")
  return first
}

interface Config { timeout?: number }
const c: Config = {} // OK — property omitted

interface ConfigExplicit { timeout?: number | undefined }
const c2: ConfigExplicit = { timeout: undefined } // OK — explicit

function isString(value: unknown): value is string {
  return typeof value === "string"
}

type Result<T> =
  | { success: true; data: T }
  | { success: false; error: Error }

function handleResult<T>(result: Result<T>): T {
  if (result.success) return result.data
  throw result.error
}

type UserId = string & { readonly __brand: "UserId" }
type OrderId = string & { readonly __brand: "OrderId" }

function createUserId(id: string): UserId { return id as UserId }
function getUser(id: UserId): User { /* ... */ }

const userId = createUserId("user-123")
const orderId = createOrderId("order-456")
getUser(userId)  // OK
getUser(orderId) // Error: OrderId not assignable to UserId

const ACTIONS = { INCREMENT: "INCREMENT", DECREMENT: "DECREMENT" } as const
type ActionType = typeof ACTIONS[keyof typeof ACTIONS]
// Type: "INCREMENT" | "DECREMENT"

function assertDefined<T>(
  value: T | null | undefined,
  message?: string
): asserts value is T {
  if (value == null) throw new Error(message ?? "Value is null or undefined")
}

const user: User | null = getUser()
assertDefined(user, "User must exist")
console.log(user.name) // user is User here

// Instead of: const user = data as User
function isUser(data: unknown): data is User {
  return (
    typeof data === "object" &&
    data !== null &&
    "id" in data &&
    "email" in data
  )
}
if (isUser(data)) { /* data is User */ }
